const body = $input.first().json.body || {};
const nowSeconds = Math.floor(Date.now() / 1000);
const THREE_YEARS_SECONDS = 3 * 365 * 24 * 60 * 60;
const errors = [];

function checkString(field, value, required, formatRegex) {
  if (value === undefined || value === null || value === '') {
    if (required) errors.push({ field, reason: 'missing' });
    return;
  }
  if (typeof value !== 'string') {
    errors.push({ field, reason: 'wrong_type' });
    return;
  }
  if (formatRegex && !formatRegex.test(value)) {
    errors.push({ field, reason: 'invalid_format' });
  }
}

function checkNumber(field, value, required, extraCheck) {
  if (value === undefined || value === null || value === '') {
    if (required) errors.push({ field, reason: 'missing' });
    return;
  }
  if (typeof value !== 'number' || Number.isNaN(value)) {
    errors.push({ field, reason: 'wrong_type' });
    return;
  }
  if (extraCheck) extraCheck(value);
}

checkString('referenceId', body.referenceId, true);
checkNumber('paymentAmount', body.paymentAmount, true, (v) => {
  if (v <= 0) errors.push({ field: 'paymentAmount', reason: 'must_be_positive' });
});
checkString('currency', body.currency, true, /^[A-Z]{3}$/);
checkString('customerEmail', body.customerEmail, true, /^[^\s@]+@[^\s@]+\.[^\s@]+$/);
checkString('invoiceNumber', body.invoiceNumber, true);
checkString('contactId', body.contactId, false);
checkString('customerName', body.customerName, false);
checkString('customerPhone', body.customerPhone, false, /^\+?[0-9]{7,15}$/);
checkString('description', body.description, false);

if (body.expireBy !== undefined && body.expireBy !== null && body.expireBy !== '') {
  if (typeof body.expireBy !== 'number' || Number.isNaN(body.expireBy)) {
    errors.push({ field: 'expireBy', reason: 'wrong_type' });
  } else if (body.expireBy <= nowSeconds) {
    errors.push({ field: 'expireBy', reason: 'in_past' });
  } else if (body.expireBy > nowSeconds + THREE_YEARS_SECONDS) {
    errors.push({ field: 'expireBy', reason: 'exceeds_max' });
  }
}

return [{
  json: {
    valid: errors.length === 0,
    errors,
    referenceId: body.referenceId,
    contactId: body.contactId,
    customerName: body.customerName,
    customerPhone: body.customerPhone,
    customerEmail: body.customerEmail,
    invoiceNumber: body.invoiceNumber,
    paymentAmount: body.paymentAmount,
    currency: body.currency,
    description: body.description,
    expireBy: body.expireBy
  }
}];

const rows = $input.all();
const row = rows[0] ? rows[0].json : {};
if (!row || !row.referenceId) {
  return [{ json: { isDuplicate: false } }];
}
const protectedStatuses = ['update_confirmed', 'link_generated', 'update_unrecoverable'];
return [{ json: {
  isDuplicate: protectedStatuses.includes(row.final_status),
  existingStatus: row.final_status,
  existingPaymentLink: row.payment_link,
  existingPaymentId: row.payment_id
} }];

const v = $('Validate Input').first().json;
return [{ json: {
  referenceId: v.referenceId,
  paymentAmount: v.paymentAmount,
  currency: v.currency,
  description: v.description,
  customerName: v.customerName,
  customerPhone: v.customerPhone,
  customerEmail: v.customerEmail,
  expireBy: v.expireBy
} }];

const item = $input.first().json;
if (item.success === true) {
  return [{ json: { success: true, payment_link: item.data.payment_link, ID: item.data.ID, referenceId: item.data.referenceId, expire_by: item.data.expire_by } }];
}
if (item.success === false) {
  return [{ json: { success: false, message: (item.error && item.error.message) || 'Sub-workflow reported failure' } }];
}
return [{ json: { success: false, message: 'Sub-workflow contract violation: ' + ((item.error && item.error.message) || 'crashed or returned unexpected shape') } }];

return [{ json: {
  referenceId: $('Validate Input').first().json.referenceId,
  link_generation_status: 'link_generation_unrecoverable',
  final_status: 'link_generation_unrecoverable',
  updated_at: new Date().toISOString(),
  error_detail: $json.message
} }];

return [{ json: {
  referenceId: $('Validate Input').first().json.referenceId,
  link_generation_status: 'link_generated',
  final_status: 'link_generated',
  payment_link: $json.payment_link,
  payment_id: $json.ID,
  expire_by: $json.expire_by,
  updated_at: new Date().toISOString()
} }];

const v = $('Validate Input').first().json;
if ($('Normalize U3 Result').isExecuted) {
  const u3 = $('Normalize U3 Result').first().json;
  return [{ json: { payment_link: u3.payment_link, ID: u3.ID, referenceId: u3.referenceId } }];
}
const dup = $('Check Duplicate').first().json;
return [{ json: { payment_link: dup.existingPaymentLink, ID: dup.existingPaymentId, referenceId: v.referenceId } }];

const item = $input.first().json;
if (item.success === true) {
  return [{ json: { success: true, payment_link: item.data.payment_link, ID: item.data.ID, referenceId: item.data.referenceId } }];
}
if (item.success === false) {
  return [{ json: { success: false, message: (item.error && item.error.message) || 'Sub-workflow reported failure' } }];
}
return [{ json: { success: false, message: 'Sub-workflow contract violation: ' + ((item.error && item.error.message) || 'crashed or returned unexpected shape') } }];

return [{ json: {
  referenceId: $('Validate Input').first().json.referenceId,
  record_update_status: 'update_unrecoverable',
  final_status: 'update_unrecoverable',
  updated_at: new Date().toISOString(),
  error_detail: $json.message
} }];

return [{ json: {
  referenceId: $('Validate Input').first().json.referenceId,
  record_update_status: 'update_confirmed',
  final_status: 'update_confirmed',
  updated_at: new Date().toISOString()
} }];

const referenceId = $('Validate Input').first().json.referenceId || null;

const response = {
  success: false,
  referenceId,
  status: 'Audit log unavailable',
  data: {
    stage: 'audit_log',
    error: { code: 'INTERNAL_ERROR', category: 'internal_error', retryable: true, message: 'Audit log unavailable' }
  }
};

const message = ':rotating_light: *Audit Log Unavailable*\n' +
  '*Reference ID:* ' + (referenceId || 'unknown') + '\n' +
  '*Details:* Google Sheets write failed - audit trail unavailable for this request.';

return [{ json: { response, message } }];

const errorMap = {
  not_retryable: { code: 'GATEWAY_REJECTED', category: 'upstream_error', retryable: false, message: 'The payment gateway rejected the request. This will not succeed on retry; please review the submitted details.' },
  malformed_response: { code: 'GATEWAY_CONTRACT_VIOLATION', category: 'upstream_error', retryable: false, message: 'The payment gateway returned an unexpected response. Please contact support.' },
  retries_exhausted_connection: { code: 'GATEWAY_TIMEOUT', category: 'upstream_error', retryable: true, message: 'The payment gateway could not be reached after multiple attempts. Please try again shortly.' },
  retries_exhausted_gateway: { code: 'GATEWAY_UNAVAILABLE', category: 'upstream_error', retryable: true, message: 'The payment gateway is currently unavailable after multiple attempts. Please try again shortly.' },
  contract_violation: { code: 'SUBWORKFLOW_CONTRACT_VIOLATION', category: 'internal_error', retryable: false, message: 'An internal error occurred while processing this request. Please contact support.' }
};
const u3 = $('Normalize U3 Result').first().json;
const mapped = errorMap[u3.reason] || { code: 'GATEWAY_ERROR', category: 'upstream_error', retryable: false, message: 'The payment gateway returned an error.' };
const referenceId = $('Validate Input').first().json.referenceId || null;

const response = {
  success: false,
  referenceId,
  status: 'Payment link generation failed',
  data: { stage: 'link_generation', error: { code: mapped.code, category: mapped.category, retryable: mapped.retryable, message: mapped.message } }
};

const message = ':rotating_light: *Payment Link Generation Failed*\n' +
  '*Reference ID:* ' + referenceId + '\n' +
  '*Stage:* link_generation\n' +
  '*Code:* ' + mapped.code + ' (' + mapped.category + ', retryable: ' + mapped.retryable + ')\n' +
  '*Details:* ' + u3.message;

return [{ json: { response, message } }];

const errorMap = {
  not_retryable: { code: 'GATEWAY_REJECTED', category: 'upstream_error', retryable: false, message: 'The payment gateway rejected the request. This will not succeed on retry; please review the submitted details.' },
  malformed_response: { code: 'GATEWAY_CONTRACT_VIOLATION', category: 'upstream_error', retryable: false, message: 'The payment gateway returned an unexpected response. Please contact support.' },
  retries_exhausted_connection: { code: 'GATEWAY_TIMEOUT', category: 'upstream_error', retryable: true, message: 'The payment gateway could not be reached after multiple attempts. Please try again shortly.' },
  retries_exhausted_gateway: { code: 'GATEWAY_UNAVAILABLE', category: 'upstream_error', retryable: true, message: 'The payment gateway is currently unavailable after multiple attempts. Please try again shortly.' },
  contract_violation: { code: 'SUBWORKFLOW_CONTRACT_VIOLATION', category: 'internal_error', retryable: false, message: 'An internal error occurred while processing this request. Please contact support.' }
};
const u4 = $('Normalize U4 Result').first().json;
const mapped = errorMap[u4.reason] || { code: 'GATEWAY_ERROR', category: 'upstream_error', retryable: false, message: 'The payment gateway returned an error.' };
const referenceId = $('Validate Input').first().json.referenceId || null;
const paymentLink = $('Build U4 Input').first().json.payment_link;

const response = {
  success: false,
  referenceId,
  status: 'Payment record update failed',
  data: { stage: 'record_update', payment_link: paymentLink, error: { code: mapped.code, category: mapped.category, retryable: mapped.retryable, message: mapped.message } }
};

const message = ':rotating_light: *Payment Record Update Failed*\n' +
  '*Reference ID:* ' + referenceId + '\n' +
  '*Stage:* record_update\n' +
  '*Payment Link:* ' + paymentLink + '\n' +
  '*Code:* ' + mapped.code + ' (' + mapped.category + ', retryable: ' + mapped.retryable + ')\n' +
  '*Details:* ' + u4.message;

return [{ json: { response, message } }];

let referenceId = null;
try {
  if ($('Validate Input').isExecuted) {
    referenceId = $('Validate Input').first().json.referenceId || null;
  }
} catch (e) {}
return [{ json: {
  success: false,
  referenceId,
  status: 'An unexpected error occurred',
  data: { stage: 'unknown', error: { code: 'UNEXPECTED_ERROR', category: 'internal_error', retryable: false, message: 'An unexpected internal error occurred while processing this request.' } }
} }];

const built = $json;
const text = ':rotating_light: *Unexpected Internal Error*\n' +
  '*Reference ID:* ' + (built.referenceId || 'unknown') + '\n' +
  '*Details:* ' + built.data.error.message;
return [{ json: { message: text } }];

const v = $('Validate Input').first().json;
const referenceId = v.referenceId || null;

const response = {
  success: false,
  referenceId,
  status: 'Validation failed',
  data: {
    stage: 'validation',
    error: { code: 'VALIDATION_ERROR', category: 'client_error', retryable: false, message: 'One or more fields failed validation' },
    fields: v.errors
  }
};

const fieldsList = v.errors.map(f => '  • ' + f.field + ': ' + f.reason).join('\n');
const message = ':rotating_light: *Validation Failed*\n' +
  '*Reference ID:* ' + (referenceId || 'unknown') + '\n' +
  '*Fields:*\n' + fieldsList;

return [{ json: { response, message } }];
